An Event Emitter in Node.js is a core concept from the 'events' module that implements the Observer/Publisher-Subscriber design pattern.

Definition:
EventEmitter is a class that allows objects to emit named events and register listener functions to those events.

Key Methods:
1. .on(eventName, listener) - Registers a listener for an event
2. .emit(eventName, [args]) - Fires/triggers the event
3. .removeListener(eventName, listener) - Removes a specific listener
4. .removeAllListeners(eventName) - Removes all listeners for an event
5. .listenerCount(eventName) - Returns the number of listeners
6. .once(eventName, listener) - Listener that fires only once

Example:
const events = require('events');
const ee = new events.EventEmitter();

ee.on('data', function(msg) {
  console.log('Received:', msg);
});

ee.emit('data', 'Hello World');
// Output: Received: Hello World

Use Cases:
- HTTP request handling
- File system events
- Custom application events
- Real-time data streams

Many Node.js built-in modules (like http, fs) are based on EventEmitter.

const events = require('events');

// Create EventEmitter instance
const myEmitter = new events.EventEmitter();

// Register callback 1: for 'start' event
myEmitter.on('start', function() {
  console.log('System started!');
});

// Register callback 2: for 'start' event (second listener)
myEmitter.on('start', function(speed) {
  console.log('Starting with speed:', speed);
});

// Register callback 3: for 'stop' event
myEmitter.on('stop', function() {
  console.log('System stopped!');
});

// Register callback 4: fires only once
myEmitter.once('error', function(msg) {
  console.log('Error occurred:', msg);
});

// Emit events
myEmitter.emit('start', 100);
myEmitter.emit('stop');
myEmitter.emit('error', 'Connection failed');
myEmitter.emit('error', 'This will not print'); // once already fired

// Output:
// System started!
// Starting with speed: 100
// System stopped!
// Error occurred: Connection failed

Node.js Events Module - Complete Guide

The 'events' module provides the EventEmitter class for handling events.

const events = require('events');
const ee = new events.EventEmitter();

// 1. .on() - Register a listener (multiple calls allowed)
ee.on('hello', function(name) {
  console.log('Hello,', name);
});

// 2. .once() - Register a listener that fires only ONCE
ee.once('login', function() {
  console.log('User logged in (fires once only)');
});

// 3. .emit() - Fire/trigger an event
ee.emit('hello', 'Alice');  // Hello, Alice
ee.emit('hello', 'Bob');    // Hello, Bob

ee.emit('login');  // User logged in (fires once only)
ee.emit('login');  // Does nothing - already fired

// 4. .removeListener() - Remove a specific listener
const fn = () => console.log('Specific listener');
ee.on('event', fn);
ee.removeListener('event', fn);
ee.emit('event'); // Nothing prints

// 5. .removeAllListeners() - Remove all listeners for an event
ee.on('test', () => console.log('test1'));
ee.on('test', () => console.log('test2'));
ee.removeAllListeners('test');
ee.emit('test'); // Nothing prints

// 6. .listenerCount() - Count listeners for an event
ee.on('count', () => {});
ee.on('count', () => {});
console.log(ee.listenerCount('count')); // 2

// 7. .listeners() - Get array of listeners
console.log(ee.listeners('hello').length); // 1

const events = require('events');
const ee = new events.EventEmitter();

// Marks of 5 subjects (out of 25 each)
const marks = [22, 19, 24, 20, 23];
const maxPerSubject = 25;
const totalSubjects = 5;

// Register 'calculate' event listener
ee.on('calculate', function() {
  let total = 0;
  for (let m of marks) {
    total += m;
  }
  console.log('Total Marks:', total + ' / ' + (maxPerSubject * totalSubjects));

  // Fire 'percentage' event with total marks as argument
  ee.emit('percentage', total);
});

// Register 'percentage' event listener
ee.on('percentage', function(total) {
  const maxTotal = maxPerSubject * totalSubjects;
  const percent = (total / maxTotal) * 100;
  console.log('Percentage:', percent.toFixed(2) + '%');
});

// Fire the 'calculate' event
ee.emit('calculate');

// Output:
// Total Marks: 108 / 125
// Percentage: 86.40%

